import time
import random
import threading
from functools import wraps

from flask import Flask, request, g, jsonify
from prometheus_client import (
    Counter,
    Gauge,
    Histogram,
    Summary,
    Info,
    generate_latest,
    CONTENT_TYPE_LATEST,
    CollectorRegistry,
    REGISTRY,
)

app = Flask(__name__)

# ──────────────────────────────────────────────
# Metrics definitions
# ──────────────────────────────────────────────

# --- Request-level metrics ---

REQUEST_COUNT = Counter(
    "http_requests_total",
    "Total number of HTTP requests",
    ["method", "endpoint", "http_status"],
)

REQUEST_LATENCY = Histogram(
    "http_request_duration_seconds",
    "HTTP request latency in seconds",
    ["method", "endpoint"],
    buckets=(0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0),
)

REQUEST_IN_PROGRESS = Gauge(
    "http_requests_in_progress",
    "Number of HTTP requests currently being processed",
    ["method", "endpoint"],
)

REQUEST_SIZE = Summary(
    "http_request_size_bytes",
    "HTTP request payload size in bytes",
    ["method", "endpoint"],
)

RESPONSE_SIZE = Summary(
    "http_response_size_bytes",
    "HTTP response payload size in bytes",
    ["method", "endpoint"],
)

# --- Business / domain metrics ---

ORDERS_CREATED = Counter(
    "business_orders_created_total",
    "Total number of orders created",
    ["product_category"],
)

ORDERS_REVENUE = Counter(
    "business_revenue_dollars_total",
    "Total revenue in dollars",
    ["product_category"],
)

ACTIVE_USERS = Gauge(
    "business_active_users",
    "Number of currently active users",
)

ITEMS_IN_CART = Gauge(
    "business_items_in_cart",
    "Current total items across all shopping carts",
)

ORDER_PROCESSING_TIME = Histogram(
    "business_order_processing_seconds",
    "Time taken to process an order",
    buckets=(0.1, 0.5, 1.0, 2.0, 5.0, 10.0, 30.0, 60.0),
)

DB_QUERY_LATENCY = Histogram(
    "db_query_duration_seconds",
    "Database query latency in seconds",
    ["query_type"],
    buckets=(0.001, 0.005, 0.01, 0.05, 0.1, 0.5, 1.0, 5.0),
)

CACHE_HITS = Counter(
    "cache_hits_total",
    "Total number of cache hits",
)

CACHE_MISSES = Counter(
    "cache_misses_total",
    "Total number of cache misses",
)

ERROR_COUNT = Counter(
    "application_errors_total",
    "Total application errors",
    ["error_type"],
)

APP_INFO = Info(
    "application",
    "Application metadata",
)
APP_INFO.info({
    "version": "1.0.0",
    "environment": "production",
    "framework": "flask",
})

# ──────────────────────────────────────────────
# Middleware – automatic per-request instrumentation
# ──────────────────────────────────────────────


@app.before_request
def _start_timer():
    g.start_time = time.time()
    method = request.method
    endpoint = request.path
    REQUEST_IN_PROGRESS.labels(method=method, endpoint=endpoint).inc()
    content_length = request.content_length or 0
    REQUEST_SIZE.labels(method=method, endpoint=endpoint).observe(content_length)


@app.after_request
def _record_metrics(response):
    method = request.method
    endpoint = request.path
    status = response.status_code

    # Don't instrument the metrics endpoint itself to avoid feedback loops
    if endpoint == "/metrics":
        return response

    latency = time.time() - g.start_time

    REQUEST_COUNT.labels(method=method, endpoint=endpoint, http_status=status).inc()
    REQUEST_LATENCY.labels(method=method, endpoint=endpoint).observe(latency)
    REQUEST_IN_PROGRESS.labels(method=method, endpoint=endpoint).dec()

    resp_size = response.content_length or 0
    RESPONSE_SIZE.labels(method=method, endpoint=endpoint).observe(resp_size)

    return response


# ──────────────────────────────────────────────
# Helper: simulate DB latency
# ──────────────────────────────────────────────

def simulate_db_query(query_type="select"):
    latency = random.uniform(0.001, 0.1)
    time.sleep(latency)
    DB_QUERY_LATENCY.labels(query_type=query_type).observe(latency)


def simulate_cache_lookup(hit_rate=0.8):
    if random.random() < hit_rate:
        CACHE_HITS.inc()
        return True
    else:
        CACHE_MISSES.inc()
        return False


