@app.route("/metrics")
def metrics():
    """Prometheus scrape endpoint."""
    return generate_latest(REGISTRY), 200, {"Content-Type": CONTENT_TYPE_LATEST}


@app.route("/")
def index():
    return jsonify({"status": "ok", "message": "Welcome to the instrumented Flask app"})


@app.route("/health")
def health():
    return jsonify({"status": "healthy"})


@app.route("/api/users", methods=["GET"])
def list_users():
    """Simulate listing users with cache + DB."""
    cache_hit = simulate_cache_lookup(hit_rate=0.7)
    if not cache_hit:
        simulate_db_query("select")

    users = [
        {"id": 1, "name": "Alice"},
        {"id": 2, "name": "Bob"},
        {"id": 3, "name": "Charlie"},
    ]
    ACTIVE_USERS.set(random.randint(50, 200))
    return jsonify(users)


@app.route("/api/users/<int:user_id>", methods=["GET"])
def get_user(user_id):
    """Simulate fetching a single user."""
    cache_hit = simulate_cache_lookup(hit_rate=0.85)
    if not cache_hit:
        simulate_db_query("select")

    if user_id > 1000:
        ERROR_COUNT.labels(error_type="not_found").inc()
        return jsonify({"error": "User not found"}), 404

    return jsonify({"id": user_id, "name": f"User-{user_id}"})


@app.route("/api/orders", methods=["POST"])
def create_order():
    """Simulate creating an order with business metrics."""
    data = request.get_json(force=True, silent=True) or {}
    category = data.get("category", "general")
    amount = data.get("amount", round(random.uniform(10, 500), 2))
    items = data.get("items", random.randint(1, 10))

    # Simulate processing
    processing_start = time.time()
    simulate_db_query("insert")
    time.sleep(random.uniform(0.05, 0.3))  # business logic
    processing_time = time.time() - processing_start

    # Record business metrics
    ORDER_PROCESSING_TIME.observe(processing_time)
    ORDERS_CREATED.labels(product_category=category).inc()
    ORDERS_REVENUE.labels(product_category=category).inc(amount)
    ITEMS_IN_CART.dec(items)  # items leave the cart

    return jsonify({
        "order_id": random.randint(10000, 99999),
        "category": category,
        "amount": amount,
        "processing_time_s": round(processing_time, 4),
    }), 201


@app.route("/api/cart/add", methods=["POST"])
def add_to_cart():
    """Simulate adding items to cart."""
    data = request.get_json(force=True, silent=True) or {}
    quantity = data.get("quantity", 1)
    ITEMS_IN_CART.inc(quantity)
    simulate_db_query("update")
    return jsonify({"message": f"Added {quantity} item(s) to cart"}), 200


@app.route("/api/cart/remove", methods=["POST"])
def remove_from_cart():
    """Simulate removing items from cart."""
    data = request.get_json(force=True, silent=True) or {}
    quantity = data.get("quantity", 1)
    ITEMS_IN_CART.dec(quantity)
    simulate_db_query("update")
    return jsonify({"message": f"Removed {quantity} item(s) from cart"}), 200


