def _background_gauge_updater():
    """Periodically update gauges to simulate a live system."""
    while True:
        ACTIVE_USERS.set(random.randint(30, 300))
        # Randomly adjust cart gauge slightly
        ITEMS_IN_CART.inc(random.randint(-2, 5))
